import { useState, useEffect, useRef } from "react";

const MILES = [
  {
    id: "first",
    label: "First Mile",
    items: [
      { num: 1, title: "Warehouse pickers",       desc: "Responsible for sorting goods at origin warehouses before dispatch." },
      { num: 2, title: "Dark-store associates",    desc: "Operate out of high-density storage units in residential clusters." },
      { num: 3, title: "Aggregation-hub handlers", desc: "Consolidate incoming shipments and prepare them for onward dispatch." },
    ],
  },
  {
    id: "middle",
    label: "Middle Mile",
    items: [
      { num: 1, title: "Truck drivers",   desc: "Transport goods between warehouses, hubs, and cities." },
      { num: 2, title: "Fleet operators", desc: "Manage movement from aggregation hubs to local distribution points." },
    ],
  },
  {
    id: "last",
    label: "Last Mile",
    items: [
      { num: 1, title: "Delivery partners", desc: "Handle final doorstep delivery — food, groceries, and parcels." },
      { num: 2, title: "Hyperlocal riders",  desc: "High attrition, constant churn, frequent relocation, and flexible partner-based models increase verification complexity and compliance risk across these segments." },
    ],
  },
];

/* ── Single layout ─────────────────────────────────────────────── */
function MileContent({ mile }) {
  return (
    <div style={{ display: "flex", gap: 72, alignItems: "flex-start", width: "100%" }}>

      {/* Image */}
      <div style={{
        flexShrink: 0, width: 320, height: 360,
        borderRadius: 10, overflow: "hidden",
        border: "1px solid #e5e5e5", background: "#f2f0ed",
        position: "relative",
      }}>
        <img
          src="/Mile.png"
          alt={mile.label}
          style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
          onError={e => {
            e.target.style.display = "none";
            const fb = e.currentTarget.parentNode.querySelector(".fb");
            if (fb) fb.style.display = "block";
          }}
        />
        {/* Collage fallback — visible only when Mile.png is missing */}
        <div className="fb" style={{
          display: "none", position: "absolute", inset: 0,
          background: "linear-gradient(150deg, #d5d2cd 0%, #b8b5b0 55%, #a8a5a0 100%)",
        }}>
          {/* Red square */}
          <div style={{ position:"absolute", top:32, left:24, width:44, height:44, background:"#e53e3e" }}/>
          {/* Tree silhouette */}
          <div style={{
            position:"absolute", top:20, right:18,
            width:60, height:120,
            background:"rgba(30,30,30,0.55)",
            clipPath:"polygon(50% 0%,100% 40%,75% 40%,75% 100%,25% 100%,25% 40%,0% 40%)",
          }}/>
          {/* Building silhouette */}
          <div style={{
            position:"absolute", top:30, left:60, right:80,
            height:160, background:"rgba(50,50,50,0.45)",
            borderRadius:"4px 4px 0 0",
          }}/>
          {/* Car silhouette */}
          <div style={{
            position:"absolute", bottom:80, left:16, width:160, height:52,
            background:"rgba(40,40,40,0.6)", borderRadius:"6px 6px 0 0",
          }}/>
          {/* Dot grid */}
          <div style={{
            position:"absolute", bottom:65, right:18,
            width:50, height:50,
            backgroundImage:"radial-gradient(circle,#999 1.5px,transparent 1.5px)",
            backgroundSize:"8px 8px", opacity:0.5,
          }}/>
          {/* Blue triangle */}
          <div style={{
            position:"absolute", bottom:68, right:20,
            width:0, height:0,
            borderLeft:"16px solid transparent",
            borderRight:"16px solid transparent",
            borderBottom:"26px solid #1a3a6b",
          }}/>
          {/* Insurance label */}
          <div style={{
            position:"absolute", bottom:0, left:0, right:0,
            background:"rgba(255,255,255,0.9)",
            padding:"8px 14px",
            fontSize:11, color:"#333", fontStyle:"italic",
            fontFamily:"Georgia,serif",
          }}>Motor Insurance.</div>
        </div>
      </div>

      {/* Text */}
      <div style={{ flex: 1, paddingTop: 8 }}>
        {mile.items.map((item, i) => (
          <div key={i} style={{ marginBottom: 44 }}>
            <h3 style={{
              fontFamily: "'Playfair Display','Georgia',serif",
              fontSize: "clamp(19px,1.55vw,25px)",
              fontWeight: 700,
              color: "#1a3a6b",
              marginBottom: 12,
              lineHeight: 1.3,
            }}>
              {item.num}.&nbsp;{item.title}
            </h3>
            <p style={{
              fontSize: "clamp(15px,1.05vw,18px)",
              color: "#444", lineHeight: 1.85,
              fontFamily: "'Inter',sans-serif",
              margin: 0,
            }}>{item.desc}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

/* ── Main ──────────────────────────────────────────────────────── */
export default function PeopleSection() {
  const [active,    setActive]    = useState(0);
  const [animState, setAnimState] = useState(null);
  // animState = { from: number, to: number, dir: "left"|"right" } | null
  const timerRef = useRef(null);

  const go = (idx) => {
    if (idx === active || animState !== null) return;
    const dir = idx > active ? "left" : "right";

    setAnimState({ from: active, to: idx, dir });

    clearTimeout(timerRef.current);
    timerRef.current = setTimeout(() => {
      setActive(idx);
      setAnimState(null);
    }, 540);
  };

  useEffect(() => () => clearTimeout(timerRef.current), []);

  // Which panels to show during animation
  const showFrom    = animState !== null;
  const fromIdx     = animState?.from;
  const toIdx       = animState?.to ?? active;
  const dir         = animState?.dir ?? "left";

  const exitAnim   = dir === "left" ? "exit-left 0.52s cubic-bezier(0.4,0,0.2,1) forwards"
                                    : "exit-right 0.52s cubic-bezier(0.4,0,0.2,1) forwards";
  const enterAnim  = dir === "left" ? "enter-right 0.52s cubic-bezier(0.4,0,0.2,1) forwards"
                                    : "enter-left 0.52s cubic-bezier(0.4,0,0.2,1) forwards";

  return (
    <section style={{ background: "#fff", padding: "100px 7vw 130px" }}>
      <style>{`
        @keyframes exit-left  { from{transform:translateX(0);opacity:1} to{transform:translateX(-100%);opacity:0} }
        @keyframes exit-right { from{transform:translateX(0);opacity:1} to{transform:translateX(100%);opacity:0}  }
        @keyframes enter-right{ from{transform:translateX(100%);opacity:0} to{transform:translateX(0);opacity:1}  }
        @keyframes enter-left { from{transform:translateX(-100%);opacity:0} to{transform:translateX(0);opacity:1} }
        @keyframes pulse-ring {
          0%  { transform:scale(1);  opacity:.85; }
          100%{ transform:scale(2);  opacity:0;   }
        }
      `}</style>

      {/* Heading */}
      <div style={{ textAlign: "center", marginBottom: 60 }}>
        <h2 style={{
          fontFamily: "'Playfair Display','Georgia',serif",
          fontSize: "clamp(42px,7.5vw,100px)",
          fontWeight: 900, color: "#1a1a1a",
          lineHeight: 1.03, margin: "0 0 24px",
        }}>
          The people who<br />powered this evolution
        </h2>
        <p style={{
          fontSize: "clamp(16px,1.2vw,20px)",
          color: "#555", lineHeight: 1.7,
          maxWidth: 660, margin: "0 auto",
          fontFamily: "'Inter',sans-serif",
        }}>
          The gig workforce spans the entire supply chain, from first-mile
          operations to last-mile delivery.
        </p>
      </div>

      {/* Timeline */}
      <div style={{
        maxWidth: 860, margin: "0 auto 56px",
        position: "relative", padding: "0 60px",
      }}>
        {/* Red line */}
        <div style={{
          position: "absolute",
          top: "calc(100% - 8px)",
          left: 60, right: 60,
          height: 2, background: "#e53e3e",
        }}/>

        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end" }}>
          {MILES.map((mile, i) => {
            const isActive = active === i;
            return (
              <button key={mile.id} onClick={() => go(i)} style={{
                background: "none", border: "none",
                cursor: animState ? "default" : "pointer",
                display: "flex", flexDirection: "column", alignItems: "center", gap: 10, padding: 0,
              }}>
                <span style={{
                  fontFamily: "'Inter',sans-serif",
                  fontSize: 16, fontWeight: 700, color: "#e53e3e",
                  opacity: isActive ? 1 : 0.5,
                  transition: "opacity 0.3s",
                }}>{mile.label}</span>

                <div style={{
                  width: isActive ? 28 : 16,
                  height: isActive ? 28 : 16,
                  borderRadius: "50%",
                  background: "#e53e3e",
                  border: isActive ? "3px solid #fff" : "none",
                  boxShadow: isActive ? "0 0 0 3px #e53e3e" : "none",
                  transition: "all 0.35s cubic-bezier(0.34,1.56,0.64,1)",
                  position: "relative",
                }}>
                  {isActive && (
                    <span style={{
                      position: "absolute", inset: -7, borderRadius: "50%",
                      border: "2px solid rgba(229,62,62,0.4)",
                      animation: "pulse-ring 1.5s ease-out infinite",
                    }}/>
                  )}
                </div>
              </button>
            );
          })}
        </div>
      </div>

      {/* Slide area */}
      <div style={{ maxWidth: 1240, margin: "0 auto" }}>
        <p style={{
          fontSize: 11, fontWeight: 800, color: "#e53e3e",
          letterSpacing: 2, textTransform: "uppercase",
          marginBottom: 36, fontFamily: "'Inter',sans-serif",
        }}>{MILES[active].label}</p>

        {/* Clip wrapper — both panels render inside, positioned absolute during anim */}
        <div style={{ position: "relative", overflow: "hidden", minHeight: 380 }}>

          {/* OUTGOING panel — slides out */}
          {showFrom && (
            <div style={{
              position: "absolute", top: 0, left: 0, right: 0,
              animation: exitAnim,
            }}>
              <MileContent mile={MILES[fromIdx]} />
            </div>
          )}

          {/* INCOMING / idle panel — slides in */}
          <div style={{
            position: showFrom ? "relative" : "relative",
            animation: showFrom ? enterAnim : "none",
            // When animating, the incoming needs to not collapse the parent height
            opacity: showFrom ? undefined : 1,
          }}>
            <MileContent mile={MILES[toIdx]} />
          </div>

        </div>
      </div>
    </section>
  );
}
